    static double calculateCircumference(double r) { return 2 * Math.PI * r; }
    static String formatResult(String label, double value) {
        return String.format("%s: %.2f", label, value);
    }
    public static void main(String[] args) {
        double r = 5;
        System.out.println(formatResult("Area", calculateArea(r)));
        System.out.println(formatResult("Circumference", calculateCircumference(r)));
    }
}

