public class Ex14 {
    static boolean isPrime(int n) {
        if (n < 2) return false;
        for (int i = 2; i * i <= n; i++) {
            if (n % i == 0) return false;
        }
        return true;
    }
    static int countPrimes(int limit) {
        int count = 0;
        for (int i = 2; i <= limit; i++) {
            if (isPrime(i)) count++;
        }
        return count;
    }
    static int[] getPrimes(int limit) {
        int count = countPrimes(limit);
        int[] primes = new int[count];
        int idx = 0;
        for (int i = 2; i <= limit; i++) {
            if (isPrime(i)) primes[idx++] = i;
        }
        return primes;
    }
    static void printArray(int[] arr) {
        for (int i = 0; i < arr.length; i++) {
            if (i > 0) System.out.print(", ");
            System.out.print(arr[i]);
        }
        System.out.println();
    }
    public static void main(String[] args) {
        int limit = 50;
        System.out.println("Primes up to " + limit + ":");
        printArray(getPrimes(limit));
        System.out.println("Count: " + countPrimes(limit));
    }
}

