hints.message:
static long factLoop(int n){long r=1;for(int i=2;i<=n;i++)r*=i;return r;}
static long factRecur(int n){return n<=1?1:n*factRecur(n-1);}
static int fibLoop(int n){if(n<=1)return n;int a=0,b=1;for(int i=2;i<=n;i++){int t=a+b;a=b;b=t;}return b;}
static int fibRecur(int n){return n<=1?n:fibRecur(n-1)+fibRecur(n-2);}
